// // This module implements a 2-to-1 multiplexer with an enable input.
// When EN is high, the output Y should be equal to B. When EN is low, the output Y should be equal to A.
module mux2to1_enable (
    input A,
    input B,
    input EN,
    output Y
);

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNA ;

    assign Y = EN ? A : B;

endmodule
